// // This module implements a combinational circuit that takes 3 input signals, a, b, and c, and produces an output signal, out. The output signal is the logical OR of the three inputs. This means that the output will be high when at least one of the inputs is high.
module and_combination (
  input a,
  input b,
  input c,
  output reg out
);

  // Implementing AND gates to generate the output
  always @(*)
    begin
      if(a && b && c)
        out = 1;
      else
        out = 0;
    end

endmodule
